    OffsetFetch getOffsetFetch(long maxRows) {
        long offset;
        if (offsetExpr != null) {
            Value v = offsetExpr.getValue(session);
            if (v == ValueNull.INSTANCE || (offset = v.getLong()) < 0) {
                throw DbException.getInvalidValueException("result OFFSET", v);
