    LocalResult finishResult(LocalResult result, long offset, long fetch, boolean fetchPercent, ResultTarget target) {
        if (offset != 0) {
            result.setOffset(offset);
        }
        if (fetch >= 0) {
            result.setLimit(fetch);
            result.setFetchPercent(fetchPercent);
            if (withTies) {
